const crypto = require('crypto');
const item = $input.first().json;
const headers = item.headers || {};
const rawBody = item.rawBody || JSON.stringify(item.body || {});
const body = typeof item.body === 'string' ? JSON.parse(item.body) : (item.body || item);
const secret = $env.LINEAR_WEBHOOK_SECRET;
if (!secret) throw new Error('LINEAR_WEBHOOK_SECRET is required');
const signature = headers['Linear-Signature'] || headers['linear-signature'];
const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
if (!signature || signature.replace(/^sha256=/, '') !== expected) throw new Error('Invalid Linear-Signature');
const data = body.data || {};
const entity = body.type || body.model || body.entity || body.resourceType;
const commentBody = data.body || '';
const markerMatch = commentBody.match(/\[SV_APPROVAL\s+([^\]]+)\]/);
if (entity !== 'Comment' || !markerMatch) return [{ json: { shouldQueue: false, reason: 'not a comment approval marker' } }];
const attrs = Object.fromEntries([...markerMatch[1].matchAll(/([A-Za-z_][A-Za-z0-9_]*)=([^\s]+)/g)].map((m) => [m[1], m[2]]));
if (attrs.decision !== 'approved' || !String(attrs.target || '').startsWith('proposal:') || !attrs.action_id) return [{ json: { shouldQueue: false, reason: 'not an approved proposal marker' } }];
const issue = data.issue || {};
const issueIdentifier = issue.identifier || data.issueIdentifier;
if (!issueIdentifier) throw new Error('Linear issue identifier missing');
return [{ json: { shouldQueue: true, row: { event_id: `evt_linear_${issueIdentifier}_${attrs.action_id}`.replace(/[^A-Za-z0-9_-]/g, '_'), created_at: new Date().toISOString(), updated_at: new Date().toISOString(), source: 'linear', source_event_id: String(body.webhookTimestamp || body.createdAt || body.id || ''), linear_issue_id: issue.id || data.issueId || '', linear_issue_identifier: issueIdentifier, linear_comment_id: data.id || '', tenant_key: '', tenant_project_id: '', type: 'linear_marker_detected', status: 'queued', priority: 2, actor_kind: 'linear_user', actor_id: (data.user || {}).id || data.userId || '', dedupe_key: `linear:${issueIdentifier}:${attrs.action_id}`, payload_json: JSON.stringify({ action_id: attrs.action_id, marker_type: 'SV_APPROVAL', target: attrs.target, decision: attrs.decision }), attempts: 0, claimed_by: '', claimed_at: '', lease_until: '', last_error: '', result_linear_comment_id: '', processed_at: '' } } }];
